/**
 * @summary Create a feed
 */
export const createFeed = (
    createFeedDto: MaybeRef<CreateFeedDto>,
 ) => {
      createFeedDto = unref(createFeedDto);
      const formData = new FormData();
formData.append('content', createFeedDto.content)
formData.append('createBy', JSON.stringify(createFeedDto.createBy));
createFeedDto.assets.forEach(value => formData.append('assets', value));
if(createFeedDto.public !== undefined) {
 formData.append('public', createFeedDto.public.toString())
 }

      return customInstance<Feed>(
      {url: `/api/feed`, method: 'POST',
      headers: {'Content-Type': 'multipart/form-data', },
       data: formData
    },
      );
    }
  


