/**
 * @summary Update a feed
 */
export const updateFeed = (
    updateFeedDto: MaybeRef<UpdateFeedDto>,
 ) => {
      updateFeedDto = unref(updateFeedDto);
      const formData = new FormData();
formData.append('content', updateFeedDto.content)
updateFeedDto.assets.forEach(value => formData.append('assets', value));
formData.append('public', updateFeedDto.public.toString())
formData.append('updateBy', JSON.stringify(updateFeedDto.updateBy));
formData.append('id', updateFeedDto.id.toString())

      return customInstance<Feed>(
      {url: `/api/feed`, method: 'PUT',
      headers: {'Content-Type': 'multipart/form-data', },
       data: formData
    },
      );
    }
  


